-- ─────────────────────────────────────────────────────────────────────────────
-- Nidara — Hyprland Lua configuration  (requires Hyprland ≥ 0.55)
-- Installed to /usr/share/nidara/config/hypr/hyprland.lua
-- Do NOT edit this file directly. Use ~/.config/nidara/hyprland-user.lua
-- for personal overrides (keyboard layout, monitors, startup apps, etc.)
-- ─────────────────────────────────────────────────────────────────────────────

-- Extend the Lua path so require() can find generated files in nidara's
-- config directory (nidara-settings.lua, nidara-monitor.lua, hyprland-user.lua)
local home = os.getenv("HOME")
package.path = package.path
    .. ";" .. home .. "/.config/nidara/?.lua"
    .. ";" .. home .. "/.config/hypr/?.lua"

-- Soft-load a module: missing files produce a notification, not a crash.
-- The handler itself is pcall-guarded: it once called a non-existent
-- hl.notify(), so the "soft" path crashed the WHOLE config load on any
-- machine missing a user .lua (caught by the CI smoke test's screenshot).
local function safe_require(mod)
    local ok, err = pcall(require, mod)
    if not ok then
        local msg = "Nidara: failed to load " .. mod .. ".lua\n" .. tostring(err)
        local notified = pcall(function()
            hl.notification.create({ text = msg, duration = 8000 })
        end)
        if not notified then print(msg) end
    end
end


